1	import { createHash } from "node:crypto";
2	import { readFileSync, statSync } from "node:fs";
3	import path from "node:path";
4	import type { ClaudeAdapter, ClaudeJsonResponse } from "./claude.js";
5	import { ERROR_CODES } from "./constants.js";
6	import type { ClusterFactsheetRecord, ClusterFileHashRecord, ClusterRecord, RouterDatabase } from "./db.js";
7	import { errorPayload, type ErrorPayload, SPEC_ERROR_MESSAGES } from "./errors.js";
8	import { pickProfile, profilePromptOptions, type ClaudeToolProfile, type ProfileAvailability, type ProfileSelection } from "./profiles.js";
9	
10	export interface ClusterConsultInput {
11	  projectId: string;
12	  clusterId: string;
13	  question: string;
14	  toolProfile?: ClaudeToolProfile | null;
15	  allowStaticFactsheet?: boolean;
16	}
17	
18	export interface ClusterConsultSuccess {
19	  cluster_id: string;
20	  factsheet_id: string;
21	  factsheet_version: number;
22	  factsheet_status: string;
23	  tool_profile: ClaudeToolProfile;
24	  profile_selection: ProfileSelection;
25	  used_fork: false;
26	  claude_session_id: string;
27	  answer: string;
28	  metrics: {
29	    duration_ms: number;
30	    tokens_in?: number;
31	    tokens_out?: number;
32	  };
33	}
34	
35	export type ClusterConsultResult = ClusterConsultSuccess | ErrorPayload;
36	
37	interface LoadedClusterContext {
38	  cluster: ClusterRecord;
39	  factsheet: ClusterFactsheetRecord;
40	  fileHashes: ClusterFileHashRecord[];
41	  factsheetContent: Record<string, unknown>;
42	}
43	
44	export async function consultCluster(
45	  db: RouterDatabase,
46	  cwd: string,
47	  claude: ClaudeAdapter,
48	  availability: ProfileAvailability,
49	  input: ClusterConsultInput
50	): Promise<ClusterConsultResult> {
51	  const loaded = loadClusterContext(db, input.projectId, input.clusterId);
52	  if ("error" in loaded) {
53	    return loaded;
54	  }
55	
56	  if (loaded.factsheet.status !== "llm_verified" && !input.allowStaticFactsheet) {
57	    return errorPayload(ERROR_CODES.CLUSTER_FACTSHEET_UNTRUSTED, SPEC_ERROR_MESSAGES[ERROR_CODES.CLUSTER_FACTSHEET_UNTRUSTED], {
58	      cluster_id: input.clusterId,
59	      reason: `Current factsheet status is ${loaded.factsheet.status}; run cluster_prepare with verification_mode=llm or pass allow_static_factsheet=true.`
60	    });
61	  }
62	
63	  const staleFiles = findStaleFiles(cwd, loaded.fileHashes);
64	  if (staleFiles.length > 0) {
65	    db.markClusterFactsheetStale(loaded.factsheet.id);
66	    db.logClusterEvent({
67	      clusterId: input.clusterId,
68	      projectId: input.projectId,
69	      eventType: "cluster_refresh_required",
70	      details: {
71	        factsheet_id: loaded.factsheet.id,
72	        factsheet_version: loaded.factsheet.version,
73	        changed_files: staleFiles
74	      }
75	    });
76	    return errorPayload(ERROR_CODES.CLUSTER_FACTSHEET_STALE, SPEC_ERROR_MESSAGES[ERROR_CODES.CLUSTER_FACTSHEET_STALE], {
77	      cluster_id: input.clusterId,
78	      details: { changed_files: staleFiles }
79	    });
80	  }
81	
82	  let profileSelection: ProfileSelection;
83	  try {
84	    profileSelection = pickProfile(input.toolProfile ?? loaded.cluster.tool_profile_default, availability);
85	  } catch (error: unknown) {
86	    return errorPayload(ERROR_CODES.CLAUDE_INVOCATION_FAILED, SPEC_ERROR_MESSAGES[ERROR_CODES.CLAUDE_INVOCATION_FAILED], {
87	      cluster_id: input.clusterId,
88	      reason: error instanceof Error ? error.message : String(error)
89	    });
90	  }
91	
92	  const start = Date.now();
93	  try {
94	    const response = claude.runPromptWithOptions
95	      ? await claude.runPromptWithOptions(buildClusterQuestionPrompt(input.question), {
96	          ...profilePromptOptions(profileSelection.selected),
97	          appendSystemPrompt: buildClusterSystemPrompt(loaded)
98	        })
99	      : await claude.runPrompt(buildClusterFallbackPrompt(loaded, input.question));
100	    const durationMs = Date.now() - start;
101	    const result: ClusterConsultSuccess = {
102	      cluster_id: input.clusterId,
103	      factsheet_id: loaded.factsheet.id,
104	      factsheet_version: loaded.factsheet.version,
105	      factsheet_status: loaded.factsheet.status,
106	      tool_profile: profileSelection.selected,
107	      profile_selection: profileSelection,
108	      used_fork: false,
109	      claude_session_id: response.sessionId,
110	      answer: response.result,
111	      metrics: {
112	        duration_ms: durationMs,
113	        tokens_in: response.tokensIn,
114	        tokens_out: response.tokensOut
115	      }
116	    };
117	    db.logClusterEvent({
118	      clusterId: input.clusterId,
119	      projectId: input.projectId,
120	      eventType: "cluster_consult",
121	      details: {
122	        factsheet_id: loaded.factsheet.id,
123	        factsheet_version: loaded.factsheet.version,
124	        factsheet_status: loaded.factsheet.status,
125	        tool_profile: profileSelection.selected,
126	        requested_profile: profileSelection.requested,
127	        downgraded: profileSelection.downgraded,
128	        used_fork: false
129	      },
130	      durationMs,
131	      tokensIn: response.tokensIn,
132	      tokensOut: response.tokensOut
133	    });
134	    if (profileSelection.downgraded) {
135	      db.logClusterEvent({
136	        clusterId: input.clusterId,
137	        projectId: input.projectId,
138	        eventType: "tool_profile_downgraded",
139	        details: profileSelection
140	      });
141	    }
142	    return result;
143	  } catch (error: unknown) {
144	    const reason = error instanceof Error ? error.message : String(error);
145	    db.logClusterEvent({
146	      clusterId: input.clusterId,
147	      projectId: input.projectId,
148	      eventType: "cluster_consult_failed",
149	      details: {
150	        reason,
151	        profile_selection: profileSelection
152	      },
153	      durationMs: Date.now() - start
154	    });
155	    return errorPayload(ERROR_CODES.CLAUDE_INVOCATION_FAILED, SPEC_ERROR_MESSAGES[ERROR_CODES.CLAUDE_INVOCATION_FAILED], {
156	      cluster_id: input.clusterId,
157	      reason
158	    });
159	  }
160	}
161	
162	function loadClusterContext(db: RouterDatabase, projectId: string, clusterId: string): LoadedClusterContext | ErrorPayload {
163	  const cluster = db.getClusterById(clusterId);
164	  if (!cluster) {
165	    return errorPayload(ERROR_CODES.CLUSTER_NOT_FOUND, SPEC_ERROR_MESSAGES[ERROR_CODES.CLUSTER_NOT_FOUND], {
166	      cluster_id: clusterId
167	    });
168	  }
169	  if (cluster.project_id !== projectId) {
170	    return errorPayload(ERROR_CODES.CLUSTER_PROJECT_MISMATCH, SPEC_ERROR_MESSAGES[ERROR_CODES.CLUSTER_PROJECT_MISMATCH], {
171	      cluster_id: clusterId
172	    });
173	  }
174	  const factsheet = db.getCurrentClusterFactsheet(clusterId);
175	  if (!factsheet) {
176	    const latestFactsheet = db.getLatestClusterFactsheet(clusterId);
177	    if (latestFactsheet?.status === "stale") {
178	      return errorPayload(ERROR_CODES.CLUSTER_FACTSHEET_STALE, SPEC_ERROR_MESSAGES[ERROR_CODES.CLUSTER_FACTSHEET_STALE], {
179	        cluster_id: clusterId,
180	        details: {
181	          factsheet_id: latestFactsheet.id,
182	          factsheet_version: latestFactsheet.version
183	        }
